<template>
  <div>
    <p>width:{{ picWidth }}</p>
    <img
      @load="isloading"
      src="data:image/jpeg;base64,"
    />
  </div>
</template>

<script>
export default {
  data(){
    return{
      picWidth: 0
    }
  },
  methods:{
    isloading(event){
      const { width } = event.target; //解構
      this.picWidth = width;
    }
  }
};
</script>

